import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import API from "../../api/api";

// ✅ SAME categories as PostProject & FindProjects
const CATEGORIES = [
  { value: "web-development",     label: "Web Development" },
  { value: "mobile-development",  label: "Mobile Development" },
  { value: "ui-ux-design",        label: "UI/UX Design" },
  { value: "graphic-design",      label: "Graphic Design" },
  { value: "backend-development", label: "Backend Development" },
  { value: "data-science",        label: "Data Science & ML" },
  { value: "devops",              label: "DevOps & Cloud" },
  { value: "content-writing",     label: "Content Writing" },
  { value: "digital-marketing",   label: "Digital Marketing" },
  { value: "video-editing",       label: "Video Editing" },
  { value: "seo",                 label: "SEO Optimization" },
  { value: "cybersecurity",       label: "Cybersecurity" },
  { value: "other",               label: "Other" },
];

// ✅ Helper to show readable label instead of raw "web-development"
const getCategoryLabel = (value) =>
  CATEGORIES.find((c) => c.value === value)?.label || value || "Other";

const formatDate = (d) => {
  if (!d) return "";
  return new Date(d).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" });
};

const MyProjects = () => {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading]   = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const fetch = async () => {
      try {
        const res = await API.get("/projects/client");
        setProjects(res.data || []);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetch();
  }, []);

  if (loading) return <div className="text-center py-10 text-gray-500">Loading...</div>;

  return (
    <div className="bg-gray-50 min-h-screen p-8">
      <div className="max-w-5xl mx-auto">

        {/* HEADER */}
        <div className="flex justify-between items-center mb-2">
          <h1 className="text-2xl font-bold text-gray-800">My Projects</h1>
          <button
            onClick={() => navigate("/client/post-project")}
            className="bg-teal-600 hover:bg-teal-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition"
          >
            + Post New Project
          </button>
        </div>
        <p className="text-gray-500 text-sm mb-6">{projects.length} projects posted</p>

        {projects.length === 0 ? (
          <div className="bg-white rounded-xl p-10 text-center text-gray-400 shadow">
            No projects posted yet.{" "}
            <span
              className="text-teal-600 cursor-pointer font-semibold"
              onClick={() => navigate("/client/post-project")}
            >
              Post one now!
            </span>
          </div>
        ) : (
          <div className="space-y-4">
            {projects.map((p) => (
              <div key={p.id} className="bg-white rounded-xl shadow p-6 border border-gray-100 hover:shadow-md transition">
                <div className="flex justify-between items-start">
                  <div className="flex-1">

                    {/* TITLE + STATUS */}
                    <div className="flex items-center gap-3 mb-1">
                      <h3 className="text-lg font-bold text-gray-800">{p.title}</h3>
                      <span className={`px-2 py-0.5 rounded-full text-xs font-semibold uppercase ${
                        p.status === "open"        ? "bg-green-100 text-green-700" :
                        p.status === "in-progress" ? "bg-blue-100 text-blue-700"  :
                        p.status === "completed"   ? "bg-gray-200 text-gray-600"  :
                                                     "bg-green-100 text-green-700"
                      }`}>
                        {p.status || "open"}
                      </span>
                    </div>

                    <p className="text-gray-500 text-sm mt-1">{p.description?.slice(0, 100)}...</p>

                    {/* META ROW */}
                    <div className="flex gap-4 mt-3 text-sm text-gray-500 flex-wrap items-center">
                      <span className="font-semibold text-gray-700">
                        💰 ₹{Number(p.budget).toLocaleString()}
                      </span>
                      {p.deadline && (
                        <span>📅 {formatDate(p.deadline)}</span>
                      )}
                      {/* ✅ FIX: Show proper label, not raw value */}
                      <span className="bg-teal-50 text-teal-700 px-2 py-0.5 rounded text-xs font-medium">
                        {getCategoryLabel(p.category)}
                      </span>
                    </div>

                    {/* SKILLS */}
                    {p.skills && (
                      <div className="flex gap-2 mt-2 flex-wrap">
                        {p.skills.split(",").map((s, i) => (
                          <span key={i} className="bg-gray-100 text-gray-600 px-2 py-0.5 rounded text-xs">
                            {s.trim()}
                          </span>
                        ))}
                      </div>
                    )}
                  </div>
                </div>

                {/* ACTION BUTTONS */}
                <div className="mt-4 border-t pt-4 flex gap-3">
                  <button
                    onClick={() => navigate(`/client/projects/${p.id}/proposals`)}
                    className="flex items-center gap-2 bg-teal-600 hover:bg-teal-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition"
                  >
                    📄 View Proposals
                  </button>
                  <button
                    onClick={() => navigate(`/client/projects/${p.id}/submissions`)}
                    className="flex items-center gap-2 bg-indigo-500 hover:bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition"
                  >
                    📤 Submissions
                  </button>
                  <button
                    onClick={() => navigate(`/client/projects/${p.id}/milestones`)}
                    className="flex items-center gap-2 bg-amber-500 hover:bg-amber-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition"
                  >
                    🎯 Milestones
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default MyProjects;
